+    ) {
+        let mut tracker = RateLimitTracker::new();
+        let now = Instant::now();
+
+        for i in 0..pane_count {
+            tracker.record_at(
+                i as u64,
+                AgentType::Codex,
+                "rule".into(),
+                Some(format!("{cooldown_secs} seconds")),
+                now,
+            );
+        }
+
+        let gc_time = now + Duration::from_secs(gc_offset_secs);
+        let panes_before = tracker.tracked_pane_count();
